package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetHeaderReturnsClone() throws Exception {
        // Create CSVFormat instance with header using reflection
        String[] header = new String[]{"col1", "col2", "col3"};

        // Create a CSVFormat instance by copying DEFAULT but injecting header via reflection
        CSVFormat format = CSVFormat.DEFAULT.withHeader(); // clear header first

        // Use reflection to set private final header field
        Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);

        // Remove final modifier using reflection (Java 12+ may require additional tricks, assumed here it's allowed)
        // For simplicity, create a new CSVFormat instance with header via withHeader method
        format = format.withHeader(header);

        // Call getHeader
        String[] result = format.getHeader();

        // Verify returned array equals original header content
        assertArrayEquals(header, result);

        // Verify returned array is a clone, not the same reference
        assertNotSame(header, result);
    }

    @Test
    void testGetHeaderReturnsNullWhenNoHeader() {
        // Create CSVFormat instance without header
        CSVFormat format = CSVFormat.DEFAULT.withHeader();

        // Call getHeader
        String[] result = format.getHeader();

        // Verify result is null
        assertNull(result);
    }
}
